// Import generated articles (30 SEO/GEO articles)
import { GENERATED_BLOG_POSTS } from './blog-data-generated';
import { FAQ_DATA } from './faq-data';

/** Add hero images and FAQ data to generated posts */
const GENERATED_WITH_EXTRAS = GENERATED_BLOG_POSTS.map((post) => ({
  ...post,
  heroImage: `/blog/${post.slug}/hero.webp`,
  faq: FAQ_DATA[post.slug] || undefined,
}));

/** Add FAQ data to hand-crafted posts (if available in FAQ_DATA) */
const BLOG_POSTS_WITH_EXTRAS = BLOG_POSTS.map((post) => ({
  ...post,
  heroImage: post.heroImage || `/blog/${post.slug}/hero.webp`,
  faq: post.faq || FAQ_DATA[post.slug] || undefined,
}));

/** All blog posts: hand-crafted + generated */
export const ALL_BLOG_POSTS: BlogPost[] = [...BLOG_POSTS_WITH_EXTRAS, ...GENERATED_WITH_EXTRAS];

export function getBlogPost(slug: string): BlogPost | undefined {
  return ALL_BLOG_POSTS.find((p) => p.slug === slug);
}

export function getBlogPostsByCategory(category: string): BlogPost[] {
  return ALL_BLOG_POSTS.filter((p) => p.category === category);
}

export function getAllBlogSlugs(): string[] {
  return ALL_BLOG_POSTS.map((p) => p.slug);
}
